import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/business/chapter-6.md","filePath":"szu/business/chapter-6.md"}'),r={name:"szu/business/chapter-6.md"};function u(o,l,s,n,c,h){return a(),e("div",null,[...l[0]||(l[0]=[t('<h2 id="第一节、企业管理概论" tabindex="-1">第一节、企业管理概论 <a class="header-anchor" href="#第一节、企业管理概论" aria-label="Permalink to &quot;第一节、企业管理概论&quot;">​</a></h2><ol><li>运作管理的概念 <ul><li>运作：泛指将投入转换为产出的过程，该过程既可以是制造有形产品，也可以是提供服务。</li><li>运作系统：组织中设计运作活动的系统</li><li>运作管理：是组织为了达成其目标，对运作系统与运作过程进行计划、组织、与控制等一系列管理工作的总称。</li><li>运作管理的基本内容 <ul><li>1.基本指导思想与运作战略决策</li><li>2.运行系统设计、构建与管理</li><li>3.运作系统的运行与管理</li><li>4.上诉三个方面的评估、完善、改进以及变革</li></ul></li></ul></li><li>运作管理的地位与作用 <ul><li>运作管理是企业基本职能活动</li><li>运作管理的任务与目标 <ul><li>1.合理利用资源</li><li>2.正确处理效率与效益问题</li><li>3.竞争优势</li></ul></li></ul></li><li>运作管理的产生与发展</li><li>网络时代对企业运作管理提出的新要求 <ul><li>1.要有高速灵敏的市场反应能力，形成敏捷供应的能力</li><li>2.形成进一步降低成本的能力，减少企业在价格竞争方面的压力</li><li>3.满足顾客的个性化需求，实施“大规模定制化”生产</li><li>4.为企业在网络时代的全球化服务提供保障</li><li>5.利用信息技术，降低企业的外部不经济性，回应全球生态保护的要求和相应的各种行动准则</li><li>6.突破“零和”博弈的旧竞争观念，倡导在网络时代的协同理念</li></ul></li></ol><h2 id="第二节、准时生产" tabindex="-1">第二节、准时生产 <a class="header-anchor" href="#第二节、准时生产" aria-label="Permalink to &quot;第二节、准时生产&quot;">​</a></h2><ol><li>准时生产的概念<br> 准时生产（Just In Time, JIT），顾名思义就是指企业只在需要的时候，按需要的量生产所需要的产品.</li><li>准时生产的实施 <ul><li>暴露问题和瓶颈</li><li>消除浪费</li><li>改进产品设计</li><li>改进工厂布局和流程设计</li><li>改进人力资源</li><li>全面质量管理</li><li>拉式调度和看板生产控制系统</li><li>与供货商紧密合作</li></ul></li><li>准时生产与制造资源计划的比较</li></ol><h2 id="第三节、敏捷制造" tabindex="-1">第三节、敏捷制造 <a class="header-anchor" href="#第三节、敏捷制造" aria-label="Permalink to &quot;第三节、敏捷制造&quot;">​</a></h2><ol><li>敏捷制造的起源</li><li>敏捷制造的概念<br> 概念：是指企业的运作具有敏捷性。<br> 敏捷制造的出发点是基于对市场发展和未来产品以及自身状况的分析，而不是单纯地利用先进技术代替人工，因而是一种更为尊重市场作用的运作管理。</li><li>敏捷制造模式中的企业组织形式 <ul><li>虚拟企业的概念</li><li>虚拟企业的特征和优势 <ul><li>特征：人力虚拟化；运作弹性化；信息网络化；组织结构动态化；并行分布式作业；</li><li>优势：有利于充分利用自身的资源优势；有利于研究开发能力的提高；有利于涉足新领域，进行多角化经营</li></ul></li><li>虚拟企业的主要形式 <ul><li>虚拟生产</li><li>虚拟开发</li><li>虚拟销售</li><li>虚拟管理</li><li>虚拟服务</li></ul></li></ul></li><li>敏捷制造模式的支撑技术 <ul><li>企业运作信息系统</li><li>企业敏捷制造的主要支撑技术 <ul><li>分布式网络通信技术</li><li>计算机集成制造（CIM）技术</li><li>计算机支持的协同工作（CSCW）技术</li><li>工作流管理（WFM）技术</li></ul></li></ul></li></ol>',6)])])}const p=i(r,[["render",u]]);export{d as __pageData,p as default};
